import React, { useState, useEffect, useContext } from 'react';
import api from '../utils/api';
import { AuthContext } from '../context/AuthContext';
import { Link } from 'react-router-dom';
import './WorkerDashboardNew.css';

const WorkerDashboard = () => {
  const { user } = useContext(AuthContext);
  const [activePage, setActivePage] = useState('dashboard');
  const [activeTab, setActiveTab] = useState('available');
  const [jobs, setJobs] = useState([]);
  const [myJobs, setMyJobs] = useState([]);
  const [earnings, setEarnings] = useState(null);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [appliedJobs, setAppliedJobs] = useState(new Set());
  const [applyingJobId, setApplyingJobId] = useState(null);
  const [profileData, setProfileData] = useState(user || {});
  const [isEditing, setIsEditing] = useState(false);
  const [monthlyEarnings, setMonthlyEarnings] = useState({});
  const [workAnalytics, setWorkAnalytics] = useState({
    dailyHours: [],
    dailyIncome: [],
    monthlyIncome: [],
    workCapacity: []
  });
  const [analyticsFilter, setAnalyticsFilter] = useState('7days');

  const categories = [
    { id: 'all', label: 'All Jobs', icon: '­¤ōŗ' },
    { id: 'painting', label: 'Painting', icon: '­¤Ä©' },
    { id: 'electrical', label: 'Electrical', icon: 'ŌÜĪ' },
    { id: 'masonry', label: 'Masonry', icon: '­¤¦▒' },
    { id: 'plumbing', label: 'Plumbing', icon: '­¤Ü░' },
    { id: 'carpentry', label: 'Carpentry', icon: '­¤¬Ü' },
    { id: 'welding', label: 'Welding', icon: '­¤öź' },
    { id: 'construction', label: 'Construction', icon: '­¤ÅŚ’ĖÅ' },
    { id: 'cleaning', label: 'Cleaning', icon: '­¤¦╣' },
    { id: 'gardening', label: 'Gardening', icon: '­¤ī▒' },
    { id: 'loading', label: 'Loading', icon: '­¤ō”' },
    { id: 'fabrication', label: 'Fabrication', icon: '­¤øĀ’ĖÅ' },
    { id: 'tiling', label: 'Tiling', icon: '­¤ōÉ' }
  ];

  const handleApplyJob = async (jobId) => {
    try {
      setApplyingJobId(jobId);
      const response = await api.post(`/jobs/${jobId}/accept`, {
        proposedRate: undefined,
        message: 'Interested in this job'
      });

      if (response.data.success) {
        setAppliedJobs(new Set([...appliedJobs, jobId]));
        alert('Ō£ģ Job application submitted successfully!');
      }
    } catch (error) {
      alert('ŌØī ' + (error.response?.data?.message || 'Failed to apply for job'));
    } finally {
      setApplyingJobId(null);
    }
  };
  const handleSaveProfile = async () => {
    try {
      const response = await api.put('/workers/profile', profileData);
      if (response.data.success) {
        alert('Ō£ģ Profile updated successfully!');
        setIsEditing(false);
      }
    } catch (error) {
      alert('ŌØī Error updating profile: ' + (error.response?.data?.message || 'Unknown error'));
    }
  };

  const handleProfileChange = (field, value) => {
    // Handle nested properties (e.g., 'location.city')
    if (field.includes('.')) {
      const [parent, child] = field.split('.');
      setProfileData({
        ...profileData,
        [parent]: {
          ...(profileData[parent] || {}),
          [child]: value
        }
      });
    } else {
      setProfileData({
        ...profileData,
        [field]: value
      });
    }
  };

  useEffect(() => {
    const fetchDashboardData = async () => {
      try {
        setLoading(true);
        const query = filter !== 'all' ? `?category=${filter}` : '';
        const [jobsRes, myJobsRes, earningsRes] = await Promise.all([
          api.get(`/workers/available-jobs${query}`),
          api.get('/workers/my-jobs?status=assigned'),
          api.get('/workers/earnings')
        ]);
        setJobs(jobsRes.data.jobs);
        setMyJobs(myJobsRes.data.jobs);
        setEarnings(earningsRes.data.earnings);
        setMonthlyEarnings(earningsRes.data.earnings?.monthlyBreakdown || {});
        
        // Fetch work analytics
        fetchWorkAnalytics();
      } catch (error) {
        console.error('Error fetching dashboard data:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchDashboardData();
  }, [filter, activePage, analyticsFilter]);

  const fetchWorkAnalytics = async () => {
    try {
      const response = await api.get(`/workers/analytics?period=${analyticsFilter}`);
      if (response.data.success) {
        setWorkAnalytics(response.data.analytics);
      }
    } catch (error) {
      console.error('Error fetching analytics:', error);
      // Fallback to mock data if API fails
      const mockAnalytics = generateMockAnalytics(analyticsFilter);
      setWorkAnalytics(mockAnalytics);
    }
  };

  const generateMockAnalytics = (filter) => {
    const days = filter === '7days' ? 7 : filter === '30days' ? 30 : 90;
    const dailyHours = [];
    const dailyIncome = [];
    const workCapacity = [];
    
    for (let i = days - 1; i >= 0; i--) {
      const date = new Date();
      date.setDate(date.getDate() - i);
      
      // Generate realistic mock data
      const hours = Math.floor(Math.random() * 10) + 4; // 4-14 hours
      const income = hours * (Math.floor(Math.random() * 300) + 200); // Ōé╣200-500 per hour
      const capacity = Math.min(100, Math.floor(hours / 12 * 100)); // Percentage capacity
      
      dailyHours.push({
        date: date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
        hours: hours
      });
      
      dailyIncome.push({
        date: date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
        income: income
      });
      
      workCapacity.push({
        date: date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
        capacity: capacity
      });
    }
    
    // Calculate monthly income
    const monthlyIncome = [
      { month: 'Jan 2024', income: 45000 },
      { month: 'Feb 2024', income: 52000 },
      { month: 'Mar 2024', income: 48000 },
      { month: 'Apr 2024', income: 55000 },
      { month: 'May 2024', income: 49000 },
      { month: 'Jun 2024', income: 58000 }
    ];
    
    return {
      dailyHours,
      dailyIncome,
      monthlyIncome,
      workCapacity
    };
  };

  const renderDashboardPage = () => {
    return (
      <div className="dashboard-page">
        <div className="page-header">
          <h1>Welcome, {user?.name}! ­¤æŗ</h1>
        </div>

        <div className="stats-section">
          <div className="stat-card">
            <div className="stat-icon">­¤ÆĄ</div>
            <div className="stat-content">
              <h4>Total Earnings</h4>
              <p className="stat-value">Ōé╣{earnings?.total || 0}</p>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon">­¤Ä»</div>
            <div className="stat-content">
              <h4>Jobs Completed</h4>
              <p className="stat-value">{earnings?.completedJobs || 0}</p>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon">ŌÅ│</div>
            <div className="stat-content">
              <h4>Pending Payments</h4>
              <p className="stat-value">Ōé╣{earnings?.pendingPayments || 0}</p>
            </div>
          </div>
        </div>

        <div className="tabs-section">
          <div className="tab-buttons">
            <button 
              className={`tab-btn ${activeTab === 'active' ? 'active' : ''}`}
              onClick={() => setActiveTab('active')}
            >
              ­¤Åó Active Jobs ({myJobs.length})
            </button>
            <button 
              className={`tab-btn ${activeTab === 'available' ? 'active' : ''}`}
              onClick={() => setActiveTab('available')}
            >
              ­¤öŹ Available Jobs ({jobs.length})
            </button>
          </div>
        </div>

        {activeTab === 'active' ? (
          <div className="tab-section">
            <div className="section-header">
              <h2>Your Active Jobs</h2>
              <p className="section-subtitle">{myJobs.length} job{myJobs.length !== 1 ? 's' : ''} in progress</p>
            </div>
            {myJobs.length > 0 ? (
              <div className="jobs-list">
                {myJobs.map(job => (
                  <div key={job._id} className="job-card active-job">
                    <div className="job-badge">ACTIVE</div>
                    <div className="job-info">
                      <h3>{job.title}</h3>
                      <p className="job-category">{job.category}</p>
                      <p className="job-employer">­¤æż {job.employer?.name}</p>
                      <p className="job-location">­¤ōŹ {job.location?.city}, {job.location?.district}</p>
                      <div className="job-meta">
                        <span>ŌÅ▒’ĖÅ Duration: {job.duration?.estimated} {job.duration?.unit}</span>
                      </div>
                    </div>
                    <div className="job-action">
                      <p className="job-price">Ōé╣{job.wageCalculation?.totalEstimated}</p>
                      <Link to={`/job/${job._id}`} className="view-btn">View Details</Link>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="empty-state">
                <p>No active jobs right now</p>
              </div>
            )}
          </div>
        ) : (
          <div className="tab-section">
            <div className="filter-section">
              <h3><span>­¤öŹ</span> Filter by Category</h3>
              <div className="filter-scroll">
                {categories.map(cat => (
                  <button 
                    key={cat.id} 
                    className={`filter-btn ${filter === cat.id ? 'active' : ''}`}
                    onClick={() => setFilter(cat.id)}
                  >
                    <span className="filter-icon">{cat.icon}</span>
                    <span className="filter-label">{cat.label}</span>
                  </button>
                ))}
              </div>
            </div>

            <div className="section-header">
              <h2>Available Jobs for You</h2>
              <p className="section-subtitle">{jobs.length} job{jobs.length !== 1 ? 's' : ''} found</p>
            </div>
            
            {jobs.length > 0 ? (
              <div className="jobs-list">
                {jobs.map(job => (
                  <div key={job._id} className="job-card available-job">
                    <div className="job-header">
                      <h3>{job.title}</h3>
                      <span className={`urgency-badge ${job.urgency}`}>­¤ö┤ {job.urgency.toUpperCase()}</span>
                    </div>
                    <p className="job-category">Category: {job.category}</p>
                    <p className="job-employer">­¤æż Posted by: {job.employer?.name}</p>
                    <p className="job-location">­¤ōŹ {job.location?.city}, {job.location?.address}</p>
                    <div className="job-details">
                      <div className="detail-item">
                        <span className="label">ŌÅ▒’ĖÅ Duration:</span>
                        <span className="value">{job.duration?.estimated} {job.duration?.unit}</span>
                      </div>
                      <div className="detail-item">
                        <span className="label">­¤Æ░ Estimated Pay:</span>
                        <span className="value price">Ōé╣{job.wageCalculation?.totalEstimated}</span>
                      </div>
                    </div>
                    <p className="job-description">{job.description?.substring(0, 100)}...</p>
                    <div className="job-action-buttons">
                      <button 
                        className="apply-btn"
                        onClick={() => handleApplyJob(job._id)}
                        disabled={appliedJobs.has(job._id) || applyingJobId === job._id}
                      >
                        {appliedJobs.has(job._id) ? 'Ō£ģ Applied' : (applyingJobId === job._id ? 'ŌÅ│ Applying...' : '­¤ōØ Apply Now')}
                      </button>
                      <Link to={`/job/${job._id}`} className="view-btn-large">View Details</Link>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="empty-state">
                <p>No jobs found matching your skills right now.</p>
                <p className="empty-hint">Check back later or explore other categories!</p>
              </div>
            )}
          </div>
        )}
      </div>
    );
  };

  const renderHistoryPage = () => {
    // Calculate averages
    const avgDailyHours = workAnalytics.dailyHours.length > 0 
      ? (workAnalytics.dailyHours.reduce((sum, item) => sum + item.hours, 0) / workAnalytics.dailyHours.length).toFixed(1)
      : 0;
    
    const avgDailyIncome = workAnalytics.dailyIncome.length > 0
      ? (workAnalytics.dailyIncome.reduce((sum, item) => sum + item.income, 0) / workAnalytics.dailyIncome.length).toFixed(0)
      : 0;
    
    const totalMonthlyIncome = workAnalytics.monthlyIncome.length > 0
      ? workAnalytics.monthlyIncome[workAnalytics.monthlyIncome.length - 1]?.income || 0
      : 0;
    
    const avgCapacity = workAnalytics.workCapacity.length > 0
      ? (workAnalytics.workCapacity.reduce((sum, item) => sum + item.capacity, 0) / workAnalytics.workCapacity.length).toFixed(0)
      : 0;
    
    return (
      <div className="history-page">
        <div className="page-header">
          <h1>­¤ōŖ Work Analytics & History</h1>
          <div className="analytics-filters">
            <select 
              value={analyticsFilter}
              onChange={(e) => {
                setAnalyticsFilter(e.target.value);
                fetchWorkAnalytics();
              }}
              className="filter-select"
            >
              <option value="7days">Last 7 Days</option>
              <option value="30days">Last 30 Days</option>
              <option value="90days">Last 90 Days</option>
            </select>
          </div>
        </div>

        {/* Summary Cards */}
        <div className="analytics-summary">
          <div className="analytic-card">
            <div className="card-icon">ŌÅ▒’ĖÅ</div>
            <div className="card-content">
              <h3>Avg Hours/Day</h3>
              <p className="card-value">{avgDailyHours} hrs</p>
              <p className="card-desc">Average working hours</p>
            </div>
          </div>
          
          <div className="analytic-card">
            <div className="card-icon">­¤Æ░</div>
            <div className="card-content">
              <h3>Daily Income</h3>
              <p className="card-value">Ōé╣{avgDailyIncome}</p>
              <p className="card-desc">Average per day</p>
            </div>
          </div>
          
          <div className="analytic-card">
            <div className="card-icon">­¤ōģ</div>
            <div className="card-content">
              <h3>Monthly Income</h3>
              <p className="card-value">Ōé╣{totalMonthlyIncome.toLocaleString()}</p>
              <p className="card-desc">Latest month</p>
            </div>
          </div>
          
          <div className="analytic-card">
            <div className="card-icon">­¤Æ¬</div>
            <div className="card-content">
              <h3>Work Capacity</h3>
              <p className="card-value">{avgCapacity}%</p>
              <p className="card-desc">Average capacity</p>
            </div>
          </div>
        </div>

        {/* Charts Section */}
        <div className="charts-section">
          <div className="chart-container">
            <h3>­¤ōł Daily Working Hours</h3>
            <div className="bar-chart">
              {workAnalytics.dailyHours.map((item, index) => (
                <div key={index} className="chart-bar">
                  <div 
                    className="bar-fill" 
                    style={{ height: `${(item.hours / 14) * 100}%` }}
                  >
                    <span className="bar-value">{item.hours}h</span>
                  </div>
                  <span className="bar-label">{item.date}</span>
                </div>
              ))}
            </div>
          </div>

          <div className="chart-container">
            <h3>­¤Æ░ Daily Income Trend</h3>
            <div className="line-chart">
              <div className="chart-grid">
                {[0, 25, 50, 75, 100].map(level => (
                  <div key={level} className="grid-line" style={{ bottom: `${level}%` }}></div>
                ))}
              </div>
              <div className="chart-line">
                {workAnalytics.dailyIncome.map((item, index) => {
                  const maxIncome = Math.max(...workAnalytics.dailyIncome.map(d => d.income));
                  const heightPercent = maxIncome > 0 ? (item.income / maxIncome) * 80 : 0;
                  return (
                    <div 
                      key={index} 
                      className="line-point"
                      style={{ 
                        left: `${(index / (workAnalytics.dailyIncome.length - 1)) * 100}%`,
                        bottom: `${heightPercent}%`
                      }}
                    >
                      <div className="point-tooltip">Ōé╣{item.income}</div>
                    </div>
                  );
                })}
              </div>
              <div className="chart-x-axis">
                {workAnalytics.dailyIncome.map((item, index) => (
                  <span key={index} className="x-label">{item.date}</span>
                ))}
              </div>
            </div>
          </div>

          <div className="chart-container">
            <h3>­¤ōŖ Monthly Income Overview</h3>
            <div className="column-chart">
              {workAnalytics.monthlyIncome.map((item, index) => (
                <div key={index} className="column-item">
                  <div 
                    className="column-bar" 
                    style={{ height: `${(item.income / 60000) * 100}%` }}
                  >
                    <span className="column-value">Ōé╣{item.income.toLocaleString()}</span>
                  </div>
                  <span className="column-label">{item.month}</span>
                </div>
              ))}
            </div>
          </div>

          <div className="chart-container">
            <h3>­¤Æ¬ Work Capacity Utilization</h3>
            <div className="capacity-chart">
              {workAnalytics.workCapacity.map((item, index) => (
                <div key={index} className="capacity-item">
                  <div className="capacity-circle">
                    <svg viewBox="0 0 36 36" className="circular-chart">
                      <path className="circle-bg"
                        d="M18 2.0845
                          a 15.9155 15.9155 0 0 1 0 31.831
                          a 15.9155 15.9155 0 0 1 0 -31.831"
                      />
                      <path className="circle"
                        strokeDasharray={`${item.capacity}, 100`}
                        d="M18 2.0845
                          a 15.9155 15.9155 0 0 1 0 31.831
                          a 15.9155 15.9155 0 0 1 0 -31.831"
                      />
                    </svg>
                    <div className="capacity-text">
                      <span className="capacity-percent">{item.capacity}%</span>
                    </div>
                  </div>
                  <span className="capacity-date">{item.date}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Earnings Summary */}
        <div className="earnings-summary">
          <div className="earn-card">
            <h3>­¤Æ░ Total Earnings</h3>
            <p className="earn-value">Ōé╣{earnings?.total || 0}</p>
          </div>
          <div className="earn-card">
            <h3>Ō£ģ Jobs Completed</h3>
            <p className="earn-value">{earnings?.completedJobs || 0}</p>
          </div>
          <div className="earn-card">
            <h3>ŌÅ│ Pending Payments</h3>
            <p className="earn-value">Ōé╣{earnings?.pendingPayments || 0}</p>
          </div>
        </div>

        <div className="monthly-breakdown">
          <h3>­¤ōģ Monthly Earnings Breakdown</h3>
          <div className="earnings-table">
            {Object.keys(monthlyEarnings).length > 0 ? (
              <table>
                <thead>
                  <tr>
                    <th>Month</th>
                    <th>Earnings</th>
                  </tr>
                </thead>
                <tbody>
                  {Object.entries(monthlyEarnings).map(([month, amount]) => (
                    <tr key={month}>
                      <td>{month}</td>
                      <td className="amount">Ōé╣{amount}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <p className="no-data">No earnings history yet</p>
            )}
          </div>
        </div>
      </div>
    );
  };

  const renderSettingsPage = () => {
    return (
      <div className="settings-page">
        <div className="page-header">
          <h1>ŌÜÖ’ĖÅ Account Settings</h1>
        </div>

        <div className="settings-container">
          <div className="settings-section">
            <h2>­¤æż Personal Information</h2>
            {isEditing ? (
              <div className="edit-form">
                <div className="form-group">
                  <label>­¤æż Full Name</label>
                  <input 
                    type="text" 
                    value={profileData.name || ''}
                    onChange={(e) => handleProfileChange('name', e.target.value)}
                  />
                </div>
                <div className="form-group">
                  <label>­¤ō× Phone Number</label>
                  <input 
                    type="text" 
                    value={profileData.phone || ''}
                    onChange={(e) => handleProfileChange('phone', e.target.value)}
                  />
                </div>
                <div className="form-group">
                  <label>­¤ōØ Bio/Description</label>
                  <textarea 
                    value={profileData.bio || ''}
                    onChange={(e) => handleProfileChange('bio', e.target.value)}
                    rows="4"
                    placeholder="Tell employers about yourself..."
                  />
                </div>
                <div className="form-actions">
                  <button className="save-btn" onClick={handleSaveProfile}>Ō£ģ Save Changes</button>
                  <button className="cancel-btn" onClick={() => setIsEditing(false)}>Ō£¢’ĖÅ Cancel</button>
                </div>
              </div>
            ) : (
              <div className="profile-view">
                <div className="info-row">
                  <span className="label">­¤æż Name:</span>
                  <span className="value">{profileData.name}</span>
                </div>
                <div className="info-row">
                  <span className="label">­¤ō× Phone:</span>
                  <span className="value">{profileData.phone}</span>
                </div>
                <div className="info-row">
                  <span className="label">­¤ō¦ Email:</span>
                  <span className="value">{profileData.email}</span>
                </div>
                <div className="info-row">
                  <span className="label">­¤ōØ Bio:</span>
                  <span className="value">{profileData.bio || 'Not set'}</span>
                </div>
                <button className="edit-btn" onClick={() => setIsEditing(true)}>Ō£Å’ĖÅ Edit Profile</button>
              </div>
            )}
          </div>

          <div className="settings-section">
            <h2>­¤ōŹ Location Details</h2>
            {isEditing ? (
              <div className="edit-form">
                <div className="form-group">
                  <label>­¤ōŹ Full Address</label>
                  <input 
                    type="text" 
                    value={profileData.location?.address || ''}
                    onChange={(e) => handleProfileChange('location.address', e.target.value)}
                  />
                </div>
                <div className="form-group">
                  <label>­¤ÅÖ’ĖÅ City</label>
                  <input 
                    type="text" 
                    value={profileData.location?.city || ''}
                    onChange={(e) => handleProfileChange('location.city', e.target.value)}
                  />
                </div>
                <div className="form-group">
                  <label>­¤ōī District</label>
                  <input 
                    type="text" 
                    value={profileData.location?.district || ''}
                    onChange={(e) => handleProfileChange('location.district', e.target.value)}
                  />
                </div>
                <div className="form-group">
                  <label>­¤Ś║’ĖÅ State</label>
                  <input 
                    type="text" 
                    value={profileData.location?.state || ''}
                    onChange={(e) => handleProfileChange('location.state', e.target.value)}
                  />
                </div>
                <div className="form-group">
                  <label>­¤ō« Pincode</label>
                  <input 
                    type="text" 
                    value={profileData.location?.pincode || ''}
                    onChange={(e) => handleProfileChange('location.pincode', e.target.value)}
                  />
                </div>
              </div>
            ) : (
              <div className="location-view">
                <div className="info-row">
                  <span className="label">­¤ōŹ Address:</span>
                  <span className="value">{profileData.location?.address || 'Not set'}</span>
                </div>
                <div className="info-row">
                  <span className="label">­¤ÅÖ’ĖÅ City:</span>
                  <span className="value">{profileData.location?.city || 'Not set'}</span>
                </div>
                <div className="info-row">
                  <span className="label">­¤ōī District:</span>
                  <span className="value">{profileData.location?.district || 'Not set'}</span>
                </div>
                <div className="info-row">
                  <span className="label">­¤Ś║’ĖÅ State:</span>
                  <span className="value">{profileData.location?.state || 'Not set'}</span>
                </div>
                <div className="info-row">
                  <span className="label">­¤ō« Pincode:</span>
                  <span className="value">{profileData.location?.pincode || 'Not set'}</span>
                </div>
              </div>
            )}
          </div>

          <div className="settings-section">
            <h2>­¤ö¦ Account Status</h2>
            {isEditing ? (
              <div className="edit-form">
                <div className="form-group">
                  <label>­¤øĀ’ĖÅ Skills (comma separated)</label>
                  <input 
                    type="text" 
                    value={profileData.skills?.join(', ') || ''}
                    onChange={(e) => handleProfileChange('skills', e.target.value.split(',').map(skill => skill.trim()))}
                    placeholder="e.g., painting, electrical, plumbing"
                  />
                </div>
                <div className="form-group">
                  <label>­¤ōŖ Expert Level</label>
                  <select 
                    value={profileData.expertLevel || 'beginner'}
                    onChange={(e) => handleProfileChange('expertLevel', e.target.value)}
                  >
                    <option value="beginner">Beginner</option>
                    <option value="intermediate">Intermediate</option>
                    <option value="expert">Expert</option>
                  </select>
                </div>
                <div className="form-group">
                  <label>ŌÅ▒’ĖÅ Availability Status</label>
                  <select 
                    value={profileData.availability?.status || 'available'}
                    onChange={(e) => handleProfileChange('availability.status', e.target.value)}
                  >
                    <option value="available">Available</option>
                    <option value="busy">Busy</option>
                    <option value="unavailable">Unavailable</option>
                  </select>
                </div>
                <div className="form-group">
                  <label>­¤Æ░ Expected Daily Rate (Ōé╣)</label>
                  <input 
                    type="number" 
                    value={profileData.expectedDailyRate || ''}
                    onChange={(e) => handleProfileChange('expectedDailyRate', parseFloat(e.target.value) || 0)}
                    placeholder="Your expected daily wage"
                  />
                </div>
              </div>
            ) : (
              <div className="status-view">
                <div className="status-item">
                  <span>­¤øĀ’ĖÅ Skills:</span>
                  <span className="skills-list">{profileData.skills?.join(', ') || 'Not set'}</span>
                </div>
                <div className="status-item">
                  <span>­¤ōŖ Expert Level:</span>
                  <span className="level-badge">{profileData.expertLevel}</span>
                </div>
                <div className="status-item">
                  <span>ŌÅ▒’ĖÅ Status:</span>
                  <span className="status-badge available">{profileData.availability?.status || 'available'}</span>
                </div>
                <div className="status-item">
                  <span>ŌŁÉ Rating:</span>
                  <span className="rating">{profileData.rating?.average || 0} ŌŁÉ ({profileData.rating?.count || 0} reviews)</span>
                </div>
                <div className="status-item">
                  <span>­¤Æ░ Expected Daily Rate:</span>
                  <span className="rate">Ōé╣{profileData.expectedDailyRate || 'Not set'}</span>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  };

  if (loading) return <div className="loading">Loading dashboard...</div>;

  return (
    <div className="worker-dashboard-new">
      {/* Sidebar Navigation */}
      <aside className="worker-sidebar">
        <div className="sidebar-header">
          <div className="worker-avatar">
            {user?.name?.charAt(0) || 'W'}
          </div>
          <h3>{user?.name}</h3>
          <p>Worker</p>
        </div>

        <nav className="sidebar-nav">
          <button 
            className={`nav-item ${activePage === 'dashboard' ? 'active' : ''}`}
            onClick={() => setActivePage('dashboard')}
          >
            <span className="nav-icon">­¤ōŖ</span> Dashboard
          </button>
          <button 
            className={`nav-item ${activePage === 'active' ? 'active' : ''}`}
            onClick={() => setActivePage('active')}
          >
            <span className="nav-icon">­¤Åó</span> Active Jobs ({myJobs.length})
          </button>
          <button 
            className={`nav-item ${activePage === 'history' ? 'active' : ''}`}
            onClick={() => setActivePage('history')}
          >
            <span className="nav-icon">­¤ōŗ</span> History
          </button>
          <button 
            className={`nav-item ${activePage === 'settings' ? 'active' : ''}`}
            onClick={() => setActivePage('settings')}
          >
            <span className="nav-icon">ŌÜÖ’ĖÅ</span> Settings
          </button>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="worker-main-content">
        {activePage === 'dashboard' && renderDashboardPage()}
        {activePage === 'active' && (
          <div className="active-jobs-page">
            <div className="page-header">
              <h1>­¤Åó Active Jobs</h1>
            </div>
            {myJobs.length > 0 ? (
              <div className="jobs-list">
                {myJobs.map(job => (
                  <div key={job._id} className="job-card active-job">
                    <div className="job-badge">ACTIVE</div>
                    <div className="job-info">
                      <h3>{job.title}</h3>
                      <p className="job-category">{job.category}</p>
                      <p className="job-employer">­¤æż {job.employer?.name}</p>
                      <p className="job-location">­¤ōŹ {job.location?.city}</p>
                    </div>
                    <div className="job-action">
                      <p className="job-price">Ōé╣{job.wageCalculation?.totalEstimated}</p>
                      <Link to={`/job/${job._id}`} className="view-btn">View Details</Link>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="empty-state">
                <p>No active jobs</p>
              </div>
            )}
          </div>
        )}
        {activePage === 'history' && renderHistoryPage()}
        {activePage === 'settings' && renderSettingsPage()}
      </main>
    </div>
  );
};

export default WorkerDashboard;
